const { Pool } = require\('pg'\);
const { v4: uuidv4 } = require\('uuid'\);
const pool = new Pool\({ connectionString: process.env.DATABASE_URL }\);
const now = new Date\(\).toISOString\(\);

async function run\(\) {
  const adminId = uuidv4\(\);
  const scopeId = uuidv4\(\);
  const assocId = 'f301d073-ed84-4d73-84ce-3ef28af66f7a'; // Cherry Hill Court Condominiums

  // Create admin user for williamruiz11
  await pool.query\(
    \\`INSERT INTO admin_users \(id, email, role, is_active, created_at, updated_at\)
     VALUES \(\\$1, \\$2, 'board-admin', 1, \\$3, \\$4\)\\`,
    [adminId, 'williamruiz11@gmail.com', now, now]
  \);
  console.log\('Created admin user:', adminId\);

  // Add association scope
  await pool.query\(
    \\`INSERT INTO admin_association_scopes \(id, admin_user_id, association_id, scope, created_at\)
     VALUES \(\\$1, \\$2, \\$3, 'admin', \\$4\)\\`,
    [scopeId, adminId, assocId, now]
  \);
  console.log\('Created scope:', scopeId\);

  // Verify
  const verify = await pool.query\(
    \\`SELECT au.email, au.role, aas.association_id, aas.scope, a.name
     FROM admin_users au
     LEFT JOIN admin_association_scopes aas ON aas.admin_user_id = au.id
     LEFT JOIN associations a ON a.id = aas.association_id
     WHERE au.email IN \('williamruiz11@gmail.com','chcmgmt18@gmail.com'\)
     ORDER BY au.email\\`
  \);
  console.log\('Final state:'\);
  verify.rows.forEach\(r => console.log\(' ', r.email, '|', r.role, '|', r.name, '|', r.scope\)\);

  await pool.end\(\);
}
run\(\).catch\(e => { console.error\(e\); process.exit\(1\); }\);
